function BFS(initialState, goalTest):
 frontier = Queue()
 frontier.enqueue(initialState)
 explored = Set()

 while frontier is not empty:
 state = frontier.dequeue()

 if goalTest(state):
 return SUCCESS(state)

 explored.add(state)

 for each action in actions(state):
 child = result(state, action)

 if child not in explored and child not in frontier:
 frontier.enqueue(child)

 return FAILURE

function A_STAR_SEARCH(initialState, goalTest):
 frontier = PriorityQueue() // Ordered by f(n)
 frontier.enqueue(initialState, key=f(initialState))
 explored = Map() // state -> g(n) cost

 while frontier is not empty:
 state = frontier.dequeue()

 if goalTest(state):
 return SUCCESS(state)

 for each action in actions(state):
 child = result(state, action)
 g_cost = g(state) + cost(state, action)
 h_cost = heuristic(child)
 f_cost = g_cost + h_cost

 if child not in explored or g_cost < explored[child]:
 explored[child] = g_cost
 frontier.enqueue(child, key=f_cost)

 return FAILURE

function g(node):
 return node.pathCost // Cost from start

function heuristic(node):
 return node.heuristic // Estimated cost to goal

function MINIMAX(state, depth, isMaximizing):
 if depth == 0 or state is terminal:
 return utility(state)

 if isMaximizing: // MAX player (AI)
 maxValue = -∞
 for each child in successors(state):
 value = MINIMAX(child, depth-1, false)
 maxValue = max(maxValue, value)
 return maxValue
 else: // MIN player (Human)
 minValue = +∞
 for each child in successors(state):
 value = MINIMAX(child, depth-1, true)
 minValue = min(minValue, value)
 return minValue

// To get the best move:
function GET_BEST_MOVE(state, depth):
 bestMove = null
 bestValue = -∞

 for each move in legalMoves(state):
 newState = applyMove(state, move)
 value = MINIMAX(newState, depth-1, false)
 if value > bestValue:
 bestValue = value
 bestMove = move

 return bestMove

function ALPHA_BETA(state, depth, alpha, beta, isMaximizing):
 if depth == 0 or state is terminal:
 return utility(state)

 if isMaximizing: // MAX player
 maxValue = -∞
 for each child in successors(state):
 value = ALPHA_BETA(child, depth-1, alpha, beta, false)
 maxValue = max(maxValue, value)
 alpha = max(alpha, value)
 if beta <= alpha:
 break // Beta cutoff (prune)
 return maxValue
 else: // MIN player
 minValue = +∞
 for each child in successors(state):
 value = ALPHA_BETA(child, depth-1, alpha, beta, true)
 minValue = min(minValue, value)
 beta = min(beta, value)
 if beta <= alpha:
 break // Alpha cutoff (prune)
 return minValue

