function HILL_CLIMBING(initialState):
 current = initialState

 while true:
 neighbor = bestSuccessor(current)

 if value(neighbor) <= value(current):
 return current // Local maximum reached

 current = neighbor

function BEST_SUCCESSOR(state):
 best = null
 bestValue = -∞

 for each successor in getSuccessors(state):
 if value(successor) > bestValue:
 best = successor
 bestValue = value(successor)

 return best

